#include <sys/stat.h>
#include <stdio.h>
#include <time.h>
#include <unistd.h>

void print_file_info(const char *path) {
    struct stat sb;
    if (lstat(path, &sb) == -1) {
        perror(path);
        return;
    }

    printf("File: %s\n", path);
    printf("  Inode: %lu\n", (unsigned long)sb.st_ino);
    printf("  Size:  %lld bytes\n", (long long)sb.st_size);
    printf("  Links: %lu\n", (unsigned long)sb.st_nlink);
    printf("  Mode:  %o\n", (unsigned int)(sb.st_mode & 07777));

    /* File type */
    printf("  Type:  ");
    if (S_ISREG(sb.st_mode))       printf("regular file\n");
    else if (S_ISDIR(sb.st_mode))  printf("directory\n");
    else if (S_ISLNK(sb.st_mode))  printf("symbolic link\n");
    else if (S_ISCHR(sb.st_mode))  printf("character device\n");
    else if (S_ISBLK(sb.st_mode))  printf("block device\n");
    else if (S_ISFIFO(sb.st_mode)) printf("FIFO\n");
    else if (S_ISSOCK(sb.st_mode)) printf("socket\n");

    /* Timestamps */
    char timebuf[64];
    struct tm *tm = localtime(&sb.st_mtime);
    strftime(timebuf, sizeof(timebuf), "%Y-%m-%d %H:%M:%S", tm);
    printf("  Modified: %s\n", timebuf);
}

int main(void) {
    print_file_info("/etc/passwd");
    print_file_info("/tmp");
    return 0;
}

