#include <sys/stat.h>
#include <stdio.h>
#include <unistd.h>

void print_permissions(const char *path) {
    struct stat sb;
    if (stat(path, &sb) == -1) { perror(path); return; }

    printf("%s: ", path);
    /* File type */
    printf("%c", S_ISDIR(sb.st_mode) ? 'd' : '-');
    /* Owner */
    printf("%c%c%c",
        (sb.st_mode & S_IRUSR) ? 'r' : '-',
        (sb.st_mode & S_IWUSR) ? 'w' : '-',
        (sb.st_mode & S_ISUID) ? 's' :
            (sb.st_mode & S_IXUSR) ? 'x' : '-');
    /* Group */
    printf("%c%c%c",
        (sb.st_mode & S_IRGRP) ? 'r' : '-',
        (sb.st_mode & S_IWGRP) ? 'w' : '-',
        (sb.st_mode & S_ISGID) ? 's' :
            (sb.st_mode & S_IXGRP) ? 'x' : '-');
    /* Other */
    printf("%c%c%c",
        (sb.st_mode & S_IROTH) ? 'r' : '-',
        (sb.st_mode & S_IWOTH) ? 'w' : '-',
        (sb.st_mode & S_ISVTX) ? 't' :
            (sb.st_mode & S_IXOTH) ? 'x' : '-');
    printf("\n");
}

int main(void) {
    print_permissions("/etc/passwd");
    print_permissions("/tmp");

    /* Change permissions */
    chmod("myfile.txt", 0755);          /* rwxr-xr-x */
    chmod("script.sh", 04755);          /* setuid + rwxr-xr-x */
    chmod("shared_dir", 01777);         /* sticky + rwxrwxrwx */

    return 0;
}

