#include <unistd.h>
#include <sys/stat.h>
#include <stdio.h>
#include <fcntl.h>
#include <string.h>

int main(void) {
    /* Create a file */
    int fd = open("original.txt", O_WRONLY | O_CREAT | O_TRUNC, 0644);
    write(fd, "hello\n", 6);
    close(fd);

    /* Create hard link */
    if (link("original.txt", "hardlink.txt") == -1)
        perror("link");

    /* Create symbolic link */
    if (symlink("original.txt", "softlink.txt") == -1)
        perror("symlink");

    /* Check link counts */
    struct stat sb;
    stat("original.txt", &sb);
    printf("original.txt: nlink=%lu, inode=%lu\n",
           (unsigned long)sb.st_nlink, (unsigned long)sb.st_ino);

    stat("hardlink.txt", &sb);
    printf("hardlink.txt: nlink=%lu, inode=%lu\n",
           (unsigned long)sb.st_nlink, (unsigned long)sb.st_ino);
    /* Same inode! nlink=2 */

    lstat("softlink.txt", &sb);
    printf("softlink.txt: inode=%lu (different), is_symlink=%d\n",
           (unsigned long)sb.st_ino, S_ISLNK(sb.st_mode));

    /* Read symlink target */
    char target[256];
    ssize_t len = readlink("softlink.txt", target, sizeof(target) - 1);
    if (len != -1) {
        target[len] = '\0';
        printf("softlink.txt -> %s\n", target);
    }

    /* Delete original -- hard link survives, symlink dangles */
    unlink("original.txt");
    /* hardlink.txt still works (nlink=1) */
    /* softlink.txt is now dangling */

    unlink("hardlink.txt");
    unlink("softlink.txt");
    return 0;
}

