#include <dirent.h>
#include <stdio.h>
#include <string.h>
#include <errno.h>

int list_directory(const char *path) {
    DIR *dp = opendir(path);
    if (dp == NULL) {
        perror(path);
        return -1;
    }

    struct dirent *entry;
    errno = 0;
    while ((entry = readdir(dp)) != NULL) {
        /* Skip . and .. */
        if (strcmp(entry->d_name, ".") == 0 ||
            strcmp(entry->d_name, "..") == 0)
            continue;

        /* Print file type (d_type is Linux-specific) */
        char type = '?';
        switch (entry->d_type) {
            case DT_REG: type = '-'; break;
            case DT_DIR: type = 'd'; break;
            case DT_LNK: type = 'l'; break;
            default:     type = '?'; break;
        }
        printf("%c %lu %s\n", type,
               (unsigned long)entry->d_ino, entry->d_name);
    }

    if (errno != 0) {
        perror("readdir");
        closedir(dp);
        return -1;
    }

    closedir(dp);
    return 0;
}

int main(void) {
    list_directory("/tmp");
    return 0;
}

