/* Approach 1: nftw (preferred) */
static int print_entry(const char *fpath, const struct stat *sb,
                       int typeflag, struct FTW *ftwbuf) {
    const char *name = fpath + ftwbuf->base;  /* just the filename */
    printf("%*s%s", ftwbuf->level * 2, "", name);
    if (typeflag == FTW_D)
        printf("/");
    printf(" (%lld bytes)\n", (long long)sb->st_size);
    return 0;  /* continue traversal */
}

/* Approach 2: Manual recursion */
void walk_dir(const char *path, int depth) {
    DIR *dp = opendir(path);
    if (dp == NULL) { perror(path); return; }

    struct dirent *entry;
    while ((entry = readdir(dp)) != NULL) {
        if (strcmp(entry->d_name, ".") == 0 ||
            strcmp(entry->d_name, "..") == 0)
            continue;

        char fullpath[PATH_MAX];
        snprintf(fullpath, sizeof(fullpath), "%s/%s", path, entry->d_name);

        struct stat sb;
        if (lstat(fullpath, &sb) == -1) continue;

        printf("%*s%s\n", depth * 2, "", entry->d_name);
        if (S_ISDIR(sb.st_mode))
            walk_dir(fullpath, depth + 1);
    }
    closedir(dp);
}

int main(void) {
    printf("=== nftw traversal ===\n");
    nftw(".", print_entry, 20, FTW_PHYS);

    printf("\n=== Manual traversal ===\n");
    walk_dir(".", 0);

    return 0;
}

