/* Atomic file update: write-to-temp then rename */
int atomic_write(const char *path, const char *data, size_t len) {
    char tmppath[256];
    snprintf(tmppath, sizeof(tmppath), "%s.tmp", path);

    /* Write to temporary file */
    int fd = open(tmppath, O_WRONLY | O_CREAT | O_TRUNC, 0644);
    if (fd == -1) { perror("open tmp"); return -1; }

    ssize_t nw = write(fd, data, len);
    if (nw != (ssize_t)len) { perror("write"); close(fd); return -1; }

    /* Ensure data is on disk before rename */
    if (fsync(fd) == -1) { perror("fsync"); close(fd); return -1; }
    close(fd);

    /* Atomic rename */
    if (rename(tmppath, path) == -1) {
        perror("rename");
        unlink(tmppath);
        return -1;
    }

    return 0;
}

int main(void) {
    const char *data = "new config data\n";
    if (atomic_write("config.txt", data, strlen(data)) == 0)
        printf("Atomically updated config.txt\n");
    else
        fprintf(stderr, "Update failed\n");
    return 0;
}

