int main(void) {
    /* Create temporary file */
    char tmpl[] = "/tmp/myapp.XXXXXX";
    int fd = mkstemp(tmpl);
    if (fd == -1) {
        perror("mkstemp");
        return 1;
    }
    printf("Temp file: %s (fd=%d)\n", tmpl, fd);

    /* Write to it */
    const char *data = "temporary data\n";
    write(fd, data, strlen(data));

    /* Unlink immediately -- file stays open until close */
    unlink(tmpl);
    printf("Unlinked %s (still usable via fd)\n", tmpl);

    /* Can still read/write via fd */
    lseek(fd, 0, SEEK_SET);
    char buf[64];
    ssize_t n = read(fd, buf, sizeof(buf) - 1);
    buf[n] = '\0';
    printf("Read back: %s", buf);

    close(fd);  /* file data now freed */

    /* Create temporary directory */
    char dtmpl[] = "/tmp/mydir.XXXXXX";
    if (mkdtemp(dtmpl) == NULL) {
        perror("mkdtemp");
        return 1;
    }
    printf("Temp dir: %s\n", dtmpl);
    rmdir(dtmpl);  /* clean up */

    return 0;
}

