int main(void) {
    /* Read current umask (no other portable way) */
    mode_t old_mask = umask(0);
    umask(old_mask);  /* restore immediately */
    printf("Current umask: %04o\n", (unsigned int)old_mask);

    /* Create file with umask 022 */
    umask(022);
    int fd1 = open("file1.txt", O_WRONLY | O_CREAT | O_TRUNC, 0666);
    /* Actual permissions: 0666 & ~022 = 0644 */

    /* Create file with umask 077 */
    umask(077);
    int fd2 = open("file2.txt", O_WRONLY | O_CREAT | O_TRUNC, 0666);
    /* Actual permissions: 0666 & ~077 = 0600 */

    /* Verify */
    struct stat sb;
    fstat(fd1, &sb);
    printf("file1.txt mode: %04o\n", (unsigned int)(sb.st_mode & 07777));  /* 0644 */
    fstat(fd2, &sb);
    printf("file2.txt mode: %04o\n", (unsigned int)(sb.st_mode & 07777));  /* 0600 */

    /* Daemon pattern: clear umask for full control */
    umask(0);
    int fd3 = open("file3.txt", O_WRONLY | O_CREAT | O_TRUNC, 0755);
    fstat(fd3, &sb);
    printf("file3.txt mode: %04o\n", (unsigned int)(sb.st_mode & 07777));  /* 0755 exactly */

    close(fd1); close(fd2); close(fd3);
    umask(old_mask);  /* restore */
    return 0;
}

