const char *file_type_str(mode_t mode) {
    if (S_ISREG(mode))  return "regular file";
    if (S_ISDIR(mode))  return "directory";
    if (S_ISLNK(mode))  return "symbolic link";
    if (S_ISCHR(mode))  return "character device";
    if (S_ISBLK(mode))  return "block device";
    if (S_ISFIFO(mode)) return "FIFO/pipe";
    if (S_ISSOCK(mode)) return "socket";
    return "unknown";
}

int main(void) {
    const char *paths[] = {
        "/etc/passwd",     /* regular file */
        "/tmp",            /* directory */
        "/dev/null",       /* character device */
        NULL
    };

    for (int i = 0; paths[i] != NULL; i++) {
        struct stat sb;
        if (lstat(paths[i], &sb) == -1) {
            perror(paths[i]);
            continue;
        }
        printf("%-20s -> %s (mode=%07o)\n",
               paths[i], file_type_str(sb.st_mode),
               (unsigned int)sb.st_mode);
    }

    /* Alternative: switch on masked mode */
    struct stat sb;
    lstat("/dev/null", &sb);
    switch (sb.st_mode & S_IFMT) {
        case S_IFCHR:  printf("/dev/null is a char device\n"); break;
        case S_IFREG:  printf("/dev/null is a regular file\n"); break;
        default:       printf("/dev/null is something else\n"); break;
    }

    return 0;
}

