#include <unistd.h>

int main(void) {
    /* Create a file */
    int fd = open("script.sh", O_WRONLY | O_CREAT | O_TRUNC, 0644);
    if (fd == -1) { perror("open"); return 1; }
    write(fd, "#!/bin/sh\necho hello\n", 21);

    /* Make executable using fchmod */
    if (fchmod(fd, 0755) == -1) perror("fchmod");
    close(fd);

    /* Verify */
    struct stat sb;
    stat("script.sh", &sb);
    printf("script.sh mode: %04o\n", (unsigned int)(sb.st_mode & 07777));
    /* Output: 0755 */

    /* Using symbolic constants */
    chmod("script.sh",
          S_IRUSR | S_IWUSR | S_IXUSR |  /* rwx for owner */
          S_IRGRP | S_IXGRP |             /* r-x for group */
          S_IROTH | S_IXOTH);             /* r-x for other */
    /* Same as 0755 */

    /* Add setuid bit */
    stat("script.sh", &sb);
    chmod("script.sh", sb.st_mode | S_ISUID);  /* setuid + existing */
    stat("script.sh", &sb);
    printf("After setuid: %04o\n", (unsigned int)(sb.st_mode & 07777));
    /* Output: 4755 */

    /* Make private (credentials file) */
    chmod("secret.key", S_IRUSR | S_IWUSR);  /* 0600 */

    unlink("script.sh");
    return 0;
}

